                        if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(restBeat)))
                        {
                            this._initFromPreviousBeat(restBeat!!, this._currentVoice)
                            restBeat!!.updateDurations()
                            this._currentVoiceState.currentPosition += restBeat!!.playbackDuration
                            this._currentVoice.addBeat(restBeat!!)
                            if (this._currentVoiceState.currentPosition >= this._currentVoiceState.currentBarDuration)
                            {
                                this._currentVoiceState.currentBarComplete = true
                            }
                        }
                    }
                    else -> { }
                }
            }
        }
    }
    
    /**
     */
    private fun _initFromPreviousBeat(chordBeat: com.omnifret.gplayer.model.Beat, currentVoice: com.omnifret.gplayer.model.Voice): Unit{
        var previousBeat: com.omnifret.gplayer.model.Beat? = this._getLastBeat(currentVoice)
        if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(previousBeat)))
        {
