    /**
     */
    private fun _getLastBeat(voice: com.omnifret.gplayer.model.Voice): com.omnifret.gplayer.model.Beat?{
        if (voice.beats.length > 0)
        {
            return voice.beats[(voice.beats.length - (1.0).toDouble()).toInt()]
        }
        if (voice.bar.index > 0)
        {
            var previousBar: com.omnifret.gplayer.model.Bar = voice.bar.staff.bars[(voice.bar.index - (1.0).toDouble()).toInt()]
            if (voice.index < previousBar.voices.length)
            {
                var previousVoice: com.omnifret.gplayer.model.Voice = previousBar.voices[(voice.index).toInt()]
                return this._getLastBeat(previousVoice)
            }
        }
        return null
    }
    
    /**
     */
    private fun _ensureVoice(staff: com.omnifret.gplayer.model.Staff, voiceIndex: Double): Unit{
        while (this._currentBar.voices.length < voiceIndex + 1.0)
        {
            this._currentBar.addVoice(com.omnifret.gplayer.model.Voice())
        }
        if (!this._voiceCounts.has(staff.track.index) || this._voiceCounts.get(staff.track.index)!! < this._currentBar.voices.length)
        {
            this._voiceCounts.set(staff.track.index, this._currentBar.voices.length)
        }
        this._currentVoice = this._currentBar.voices[(voiceIndex).toInt()]
    }
    
    /**
     */
    private fun _parseChord(beat: com.omnifret.gplayer.model.Beat, element: com.omnifret.gplayer.xml.XmlNode): Unit{
        var articulation: com.omnifret.gplayer.model.Note = com.omnifret.gplayer.model.Note()
        for (c in element.childElements())
        {
            when (c.localName)
            {
                "stem" -> 
                {
                    when (c.getAttribute("dir"))
                    {
                        "up" -> 
                        {
                            beat.preferredBeamDirection = com.omnifret.gplayer.rendering.utils.BeamDirection.Up
                        }
                        "down" -> 
                        {
                            beat.preferredBeamDirection = com.omnifret.gplayer.rendering.utils.BeamDirection.Down
                        }
                        else -> { }
                    }
                }
                "articulation" -> 
                {
                    when (c.getAttribute("type"))
                    {
                        "staccato" -> 
                        {
                            articulation.isStaccato = true
                        }
                        "normalAccent" -> 
                        {
                            articulation.accentuated = com.omnifret.gplayer.model.AccentuationType.Normal
                        }
                        "strongAccent" -> 
                        {
                            articulation.accentuated = com.omnifret.gplayer.model.AccentuationType.Heavy
                        }
                        else -> { }
                    }
                }
                "lyric" -> 
                {
                    this._parseLyric(beat, c)
                }
                "drawObjects" -> 
                {
                    this._parseBeatDrawObject(beat, c)
                }
                "heads" -> 
                {
                    this._parseHeads(beat, articulation, c)
                }
                "beam" -> 
                {
                    when (c.getAttribute("group"))
                    {
                        "force" -> 
                        {
                            beat.beamingMode = com.omnifret.gplayer.model.BeatBeamingMode.ForceMergeWithNext
                        }
                        "divide" -> 
                        {
                            beat.beamingMode = com.omnifret.gplayer.model.BeatBeamingMode.ForceSplitToNext
                        }
                        else -> { }
                    }
                }
                else -> { }
            }
        }
    }
    
    /**
     */
