    /**
     */
    private fun _parseHead(beat: com.omnifret.gplayer.model.Beat, articulation: com.omnifret.gplayer.model.Note, element: com.omnifret.gplayer.xml.XmlNode): Unit{
        var note: com.omnifret.gplayer.model.Note = com.omnifret.gplayer.model.Note()
        var pitch: com.omnifret.gplayer.model.TuningParseResult? = com.omnifret.gplayer.model.ModelUtils.parseTuning(element.getAttribute("pitch"))
        note.octave = pitch!!.octave - (1.0).toDouble()
        note.tone = pitch!!.tone.noteValue
        note.isStaccato = articulation.isStaccato
        note.accentuated = articulation.accentuated
        beat.addNote(note)
        for (c in element.childElements())
        {
            when (c.localName)
            {
                "alter" -> 
                {
                    if (c.attributes.has("step"))
                    {
                        note.tone += com.omnifret.gplayer.core.ecmaScript.Number.parseInt(c.attributes.get("step")!!, 10.0)
                    }
                }
                "tie" -> 
                {
                    if (c.attributes.has("begin"))
                    {
                        if (!this._tieStartIds.has(note.id))
                        {
                            this._tieStartIds.set(note.id, true)
                            this._tieStarts.push(note)
                        }
                    }
                    else if (c.attributes.has("end") && this._tieStarts.length > 0 && !note.isTieDestination)
                    {
                        note.isTieDestination = true
                        note.tieOrigin = this._tieStarts[(0).toInt()]
                        this._tieStarts.splice(0.0, 1.0)
                        this._tieStartIds.delete(note.id)
                    }
                }
                else -> { }
            }
        }
    }
    
