    /**
     */
    private fun _applyVolta(obj: com.omnifret.gplayer.importer.VoltaDrawObject): Unit{
        if (obj.lastNumber > 0)
        {
            this._currentVoiceState.repeatCount = obj.lastNumber
            if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(this._currentVoiceState.repeatEnd)) && this._currentVoiceState.repeatEnd!!.repeatCount < this._currentVoiceState.repeatCount))
            {
                this._currentVoiceState.repeatEnd!!.repeatCount = this._currentVoiceState.repeatCount
            }
        }
        else if (obj.firstNumber > 0)
        {
            this._currentVoiceState.repeatCount = obj.firstNumber
            if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(this._currentVoiceState.repeatEnd)) && this._currentVoiceState.repeatEnd!!.repeatCount < this._currentVoiceState.repeatCount))
            {
                this._currentVoiceState.repeatEnd!!.repeatCount = this._currentVoiceState.repeatCount
            }
        }
        if (obj.lastNumber > 0 && obj.firstNumber > 0)
        {
            var alternateEndings: Double = 0.0
            if (true) {
                var i: Double = obj.firstNumber
                
                while(i <= obj.lastNumber){
                    alternateEndings = ((alternateEndings).toInt() or (1 shl ((i - (1.0).toDouble())).toInt())).toDouble()
                    i++
                }
            }
            this._currentBar.masterBar.alternateEndings = alternateEndings
        }
        else if (obj.lastNumber > 0)
        {
            this._currentBar.masterBar.alternateEndings = (1 shl ((obj.lastNumber - (1.0).toDouble())).toInt()).toDouble()
        }
        else if (obj.firstNumber > 0)
        {
            this._currentBar.masterBar.alternateEndings = (1 shl ((obj.firstNumber - (1.0).toDouble())).toInt()).toDouble()
        }
    }
    
