    /**
     */
    private fun _parseRestDurations(element: com.omnifret.gplayer.xml.XmlNode): com.omnifret.gplayer.model.Beat?{
        var durationBase: String = element.getAttribute("base")
        if (durationBase.indexOfInDouble("/") != -1.0)
        {
            var restBeat: com.omnifret.gplayer.model.Beat = com.omnifret.gplayer.model.Beat()
            restBeat.beamingMode = this._beamingMode
            this._parseDuration(restBeat, element)
            return restBeat
        }
        var fullBars: Double = com.omnifret.gplayer.core.ecmaScript.Number.parseInt(durationBase, 10.0)
        if (fullBars == 1.0)
        {
            var restBeat: com.omnifret.gplayer.model.Beat = com.omnifret.gplayer.model.Beat()
            restBeat.beamingMode = this._beamingMode
            restBeat.duration = com.omnifret.gplayer.model.Duration.Whole
            return restBeat
        }
        com.omnifret.gplayer.Logger.warning("Importer", "Multi-Bar rests are not supported")
        return null
    }
    
