            }
            "1/32" -> 
            {
                return com.omnifret.gplayer.model.Duration.ThirtySecond
            }
            "1/64" -> 
            {
                return com.omnifret.gplayer.model.Duration.SixtyFourth
            }
            "1/128" -> 
            {
                return com.omnifret.gplayer.model.Duration.OneHundredTwentyEighth
            }
            else -> 
            {
                com.omnifret.gplayer.Logger.warning("Importer", "Unsupported duration")
