    /**
     */
    private fun _parseDuration(beat: com.omnifret.gplayer.model.Beat, element: com.omnifret.gplayer.xml.XmlNode): Unit{
        var durationBase: String = element.getAttribute("base")
        beat.duration = this._parseDurationValue(durationBase)
        if (element.attributes.has("dots"))
        {
            beat.dots = com.omnifret.gplayer.core.ecmaScript.Number.parseInt(element.attributes.get("dots")!!, 10.0)
        }
        var tuplet: com.omnifret.gplayer.xml.XmlNode? = element.findChildElement("tuplet")
        if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(tuplet)))
        {
            beat.tupletNumerator = com.omnifret.gplayer.core.ecmaScript.Number.parseInt(tuplet!!.getAttribute("count"), 10.0)
            var tripartiteMultiplicator: Double = if(tuplet!!.getAttribute("tripartite") == "true")  3.0 else 1.0
            var prolongDiff: Double = if(tuplet!!.getAttribute("prolong") == "true")  0.0 else 1.0
            var power: Double = 0.0
            while (tripartiteMultiplicator * com.omnifret.gplayer.core.ecmaScript.Math.pow(2.0, power + prolongDiff) < beat.tupletNumerator)
            {
                power++
            }
            beat.tupletDenominator = tripartiteMultiplicator * com.omnifret.gplayer.core.ecmaScript.Math.pow(2.0, power)
        }
    }
    
