    /**
     */
    private fun _parseDrawObj(element: com.omnifret.gplayer.xml.XmlNode): com.omnifret.gplayer.importer.DrawObject?{
        var obj: com.omnifret.gplayer.importer.DrawObject? = null
        var noteRange: Double = 1.0
        for (c in element.childElements())
        {
            when (c.localName)
            {
                "text" -> 
                {
                    obj = this._parseText(c)
                }
                "guitar" -> 
                {
                    obj = this._parseGuitar(c)
                }
                "slur" -> 
                {
                    obj = this._parseSlur(c)
                }
                "wavyLine" -> 
                {
                    obj = this._parseWavyLine(c)
                }
                "bracket" -> 
                {
                    obj = this._parseTupletBracket(c)
                }
                "wedge" -> 
                {
                    obj = this._parseWedge(c)
                }
                "volta" -> 
                {
                    obj = this._parseVolta(c)
                }
                "octaveClef" -> 
                {
                    obj = this._parseOctaveClef(c)
                }
                "trill" -> 
                {
                    obj = this._parseTrill(c)
                }
                "basic" -> 
                {
                    if (c.attributes.has("noteRange"))
                    {
                        noteRange = com.omnifret.gplayer.core.ecmaScript.Number.parseInt(c.attributes.get("noteRange")!!, 10.0)
                    }
                }
                else -> { }
            }
        }
        if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(obj)))
        {
            obj!!.noteRange = noteRange
        }
        return obj
    }
    
