        var obj: com.omnifret.gplayer.importer.VoltaDrawObject = com.omnifret.gplayer.importer.VoltaDrawObject()
        obj.allNumbers = element.attributes.get("allNumbers") == "true"
        if (element.attributes.has("firstNumber"))
