    /**
     */
    private fun _parseGuitar(element: com.omnifret.gplayer.xml.XmlNode): com.omnifret.gplayer.importer.GuitarDrawObject{
        var obj: com.omnifret.gplayer.importer.GuitarDrawObject = com.omnifret.gplayer.importer.GuitarDrawObject()
        var strings: String = element.innerText.trim()
        if (true) {
            var i: Double = 0.0
            
            while(i < strings.length.toDouble()){
                if (strings.charAt(i) == "/")
                {
                    obj.chord.strings.push(0.0)
                }
                else 
                {
                    obj.chord.strings.push(com.omnifret.gplayer.core.ecmaScript.Number.parseInt(strings.charAt(i), 10.0))
                }
                i++
            }
        }
        return obj
    }
    
    /**
     */
    private fun _parseText(element: com.omnifret.gplayer.xml.XmlNode): com.omnifret.gplayer.importer.TextDrawObject{
        var obj: com.omnifret.gplayer.importer.TextDrawObject = com.omnifret.gplayer.importer.TextDrawObject()
        if (element.attributes.has("x"))
        {
            obj.x = com.omnifret.gplayer.core.ecmaScript.Number.parseFloat(element.attributes.get("x")!!)
        }
        if (element.attributes.has("x"))
        {
            obj.y = com.omnifret.gplayer.core.ecmaScript.Number.parseFloat(element.attributes.get("y")!!)
        }
        when (element.getAttribute("align"))
        {
            "left" -> 
            {
                obj.align = com.omnifret.gplayer.platform.TextAlign.Left
            }
            "center" -> 
            {
                obj.align = com.omnifret.gplayer.platform.TextAlign.Center
            }
            "right" -> 
            {
                obj.align = com.omnifret.gplayer.platform.TextAlign.Right
            }
            else -> { }
        }
        when (element.getAttribute("frame"))
        {
            "rectangle" -> 
            {
                obj.frame = com.omnifret.gplayer.importer.FrameType.Rectangle
            }
            "ellipse" -> 
            {
                obj.frame = com.omnifret.gplayer.importer.FrameType.Ellipse
            }
            "circle" -> 
            {
                obj.frame = com.omnifret.gplayer.importer.FrameType.Circle
            }
            "none" -> 
            {
                obj.frame = com.omnifret.gplayer.importer.FrameType.None
            }
            else -> { }
        }
        if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(element.firstElement)))
        {
            for (c in element.childElements())
            {
                when (c.localName)
                {
                    "font" -> 
                    {
                        obj.fontFace = c.getAttribute("face")
                        if (c.attributes.has("weight"))
                        {
                            obj.weight = com.omnifret.gplayer.core.ecmaScript.Number.parseInt(c.attributes.get("weight")!!, 10.0)
                        }
                        if (c.attributes.has("height"))
                        {
                            obj.height = com.omnifret.gplayer.core.ecmaScript.Number.parseInt(c.attributes.get("height")!!, 10.0)
                        }
                    }
                    "content" -> 
                    {
                        obj.text = c.innerText
                    }
                    else -> { }
                }
            }
        }
        else 
        {
            obj.text = element.innerText
        }
        return obj
    }
    
    /**
     */
    private fun _parseInfo(element: com.omnifret.gplayer.xml.XmlNode): Unit{
        for (c in element.childElements())
        {
            when (c.localName)
            {
                "author" -> 
                {
                    this.score.tab = c.firstChild!!.innerText
                }
                "comment" -> 
                {
                    this.score.notices = c.firstChild!!.innerText
                }
                else -> { }
            }
        }
    }
    
    companion object{
        /**
         */
        @kotlin.jvm.JvmStatic
        private fun <T>_applyEffectRange(effects: com.omnifret.gplayer.collections.Map<com.omnifret.gplayer.model.Beat, T>, applyEffect: ((arg1: T, arg2: com.omnifret.gplayer.model.Beat) -> Unit)): Unit
            where T : com.omnifret.gplayer.importer.DrawObject{
            for ((startBeat, effect) in effects)
            {
                var noteRange: Double = effect.noteRange
                var endBeat: com.omnifret.gplayer.model.Beat = startBeat
                if (true) {
                    var i: Double = 0.0
                    
                    while(i < noteRange){
                        applyEffect(effect, endBeat)
                        if (endBeat.index + 1.0 < endBeat.voice.beats.length)
                        {
                            endBeat = endBeat.voice.beats[(endBeat.index + 1.0).toInt()]
                        }
                        else if (endBeat.voice.bar.index + 1.0 < endBeat.voice.bar.staff.bars.length)
                        {
                            var nextBar: com.omnifret.gplayer.model.Bar = endBeat.voice.bar.staff.bars[(endBeat.voice.bar.index + 1.0).toInt()]
                            endBeat = nextBar.voices[(endBeat.voice.index).toInt()].beats[(0).toInt()]
                        }
                        else 
                        {
                            break
                        }
                        i++
                    }
                }
            }
        }
        
    }
    public constructor()
}

