internal enum class FrameType(override val value: Int): com.omnifret.gplayer.core.IGPlayerEnum
{
    None(0),
    Rectangle(1),
    Ellipse(2),
    Circle(3);
    companion object : com.omnifret.gplayer.core.IGPlayerEnumCompanion<FrameType>{
        public override val values = arrayOf(None, Rectangle, Ellipse, Circle) 
        public override fun fromValue(v:Double): FrameType{
            return when(v.toInt()){
                None.value -> None
                Rectangle.value -> Rectangle
                Ellipse.value -> Ellipse
                Circle.value -> Circle
                else -> throw ClassCastException("No enum with value $v found")}
        }
    }
}

